import { readFileSync } from 'node:fs';

// Real Supabase credentials from env (service role key for direct read access)
const SUPABASE_URL = 'https://kvclcdjmjghndxsngfzb.supabase.co';
const SERVICE_ROLE = (readFileSync('expo/.env', 'utf8').match(/^SUPABASE_SERVICE_ROLE_KEY=(.+)$/m) || [])[1]?.trim();

if (!SERVICE_ROLE) {
  console.log('MISSING_SERVICE_ROLE_KEY');
  process.exit(1);
}

const headers = {
  apikey: SERVICE_ROLE,
  Authorization: `Bearer ${SERVICE_ROLE}`,
};

async function openRecord(table, idColumn, id, label) {
  const url = `${SUPABASE_URL}/rest/v1/${table}?${idColumn}=eq.${encodeURIComponent(id)}&limit=1`;
  try {
    const res = await fetch(url, { headers });
    const status = res.status;
    const json = await res.json();
    const row = Array.isArray(json) ? json[0] : null;
    const found = !!row;
    console.log(JSON.stringify({
      step: label,
      table,
      idColumn,
      id,
      http: status,
      found,
      created_at: row?.created_at || null,
      row_keys: row ? Object.keys(row).slice(0, 12) : null,
      sample: row ? { email: row.email, name: row.name, source: row.source, status: row.status, action: row.action, intent_score: row.intent_score, keyword: row.keyword } : null,
      verified_from_production_db: found,
    }));
  } catch (e) {
    console.log(JSON.stringify({ step: label, table, id, error: String(e).slice(0,200), verified_from_production_db: false }));
  }
}

// Open each of the 10 production records from the live database
const records = [
  ['waitlist', 'id', '1a6ed87e-fc9c-4cc2-bd37-32798b85951c', '1_waitlist_record'],
  ['members', 'member_id', '14a484e0-dc93-49fd-b11a-72dec500a96c', '2_member_id'],
  ['investors', 'id', '403c322b-8610-40af-9876-3f77ee96b3a1', '3_investor_crm_id'],
  ['analytics_events', 'id', '106636ae-67a6-4796-be4e-8223f87c3dbe', '4_analytics_event_id'],
  ['notifications', 'id', 'notif-f2c6b367-266b-4d92-9d45-18c582336da7', '5a_email_job_id_1'],
  ['sms_messages', 'id', '5b691141-2fc6-4575-8ab3-fe059e754bd3', '5b_sms_job_id'],
  ['notifications', 'id', 'notif-a910238b-b2d6-4d33-a56e-bd183ddd5d21', '5c_email_job_id_2'],
  ['ivx_intent_audit', 'id', 'f240e5d3-c9e9-47b2-b835-eccbcc315467', '6_audit_log_id'],
  ['ivx_intent_keywords', 'id', '7dbc4529-0d51-4b60-9091-1ddd14cffe88', '7_keyword_id'],
  ['ivx_visitor_intelligence', 'id', 'd2e9b4da-bbf1-467f-a213-21d533e7bb6d', '8_visitor_intelligence_id'],
];

for (const [table, col, id, label] of records) {
  await openRecord(table, col, id, label);
}

// Dashboard counts before/after (live count query)
async function count(table) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?select=id&limit=1000`, { headers });
    const json = await res.json();
    const n = Array.isArray(json) ? json.length : 0;
    console.log(JSON.stringify({ count_table: table, http: res.status, count: n }));
  } catch (e) {
    console.log(JSON.stringify({ count_table: table, error: String(e).slice(0,200) }));
  }
}

console.log('---DASHBOARD_COUNTS_LIVE---');
await count('waitlist');
await count('members');
await count('investors');
await count('analytics_events');
await count('notifications');
await count('sms_messages');
await count('ivx_intent_keywords');
await count('ivx_visitor_intelligence');
await count('ivx_intent_audit');

